beginner_examples.query:
db.students.aggregate([
  { $bucket: {
      groupBy: '$gpa',
      boundaries: [3.0, 3.5, 4.0],
      output: {
        count: { $sum: 1 },
        avgAge: { $avg: '$age' }
      }
    }
  }
])

db.students.aggregate([
  { $bucket: {
      groupBy: '$age',
      boundaries: [18, 25, 35, 45],
      default: 'other',
      output: {
        count: { $sum: 1 },
        avgGpa: { $avg: '$gpa' },
        students: { $push: '$name' }
      }
    }
  }
])

intermediate_examples.query:
db.students.aggregate([
  { $match: { major: 'CS' } },
  { $bucket: {
      groupBy: '$gpa',
      boundaries: [3.0, 3.5, 4.0],
      output: {
        count: { $sum: 1 },
        maxAge: { $max: '$age' },
        minAge: { $min: '$age' }
      }
    }
  }
])

db.students.aggregate([
  { $bucket: {
      groupBy: '$scholarshipDetails.amount',
      boundaries: [0, 10000, 20000, 30000, 50000],
      default: 'no-scholarship',
      output: {
        count: { $sum: 1 },
        avgGpa: { $avg: '$gpa' },
        totalAmount: { $sum: '$scholarshipDetails.amount' }
      }
    }
  }
])

db.students.aggregate([
  { $bucketAuto: {
      groupBy: '$gpa',
      buckets: 4,
      output: {
        count: { $sum: 1 },
        avgAge: { $avg: '$age' },
        maxGpa: { $max: '$gpa' }
      }
    }
  }
])

advanced_examples.query:
db.students.aggregate([
  { $bucket: {
      groupBy: '$age',
      boundaries: [18, 25, 35, 45, 55],
      output: {
        count: { $sum: 1 },
        avgGpa: { $avg: '$gpa' },
        totalStudents: { $sum: 1 }
      }
    }
  },
  { $sort: { count: -1 } }
])

db.students.aggregate([
  { $group: {
      _id: '$major',
      avgGpa: { $avg: '$gpa' }
    }
  },
  { $bucket: {
      groupBy: '$avgGpa',
      boundaries: [3.0, 3.5, 4.0],
      output: { majors: { $push: '$_id' } }
    }
  }
])

db.students.aggregate([
  { $bucket: {
      groupBy: '$age',
      boundaries: [18, 25, 35],
      default: 'other',
      output: {
        count: { $sum: 1 },
        highAchievers: { $sum: { $cond: [{ $gte: ['$gpa', 3.8] }, 1, 0] } }
      }
    }
  }
])
